const crypto = require('crypto');

const headers = $json.headers;
// Webhookノードのoptions.rawBody:trueは生ボディをbinary.data.data(base64)へ格納する。
// bare $binary は n8n(JS Task Runner)の静的built-ins解析で認識されず未定義になるため、
// $input経由(認識対象)でアイテムを取得してからbinaryを読む必要がある(実機検証で確認済み)。
const item = $input.first();
const rawBody = item.binary?.data?.data
  ? Buffer.from(item.binary.data.data, 'base64').toString('utf-8')
  : '';
const timestamp = headers['x-slack-request-timestamp'];
const sigHeader = headers['x-slack-signature'];
const signingSecret = $env.SLACK_SIGNING_SECRET;

// リプレイ攻撃対策: 5分以上ずれたタイムスタンプは拒否
const fiveMinutes = 60 * 5;
if (Math.abs(Math.floor(Date.now() / 1000) - Number(timestamp)) > fiveMinutes) {
  throw new Error('Slack request timestamp too old (possible replay)');
}

const baseString = `v0:${timestamp}:${rawBody}`;
const hmac = crypto.createHmac('sha256', signingSecret).update(baseString).digest('hex');
const expectedSig = `v0=${hmac}`;

if (expectedSig !== sigHeader) {
  throw new Error('Invalid Slack signature (slash command)');
}

const body = $json.body; // command, text, user_id, user_name, trigger_id, channel_id, response_url
const today = new Date().toISOString().slice(0, 10);

const modal_view = {
  type: 'modal',
  callback_id: 'invoice_create_modal',
  title: { type: 'plain_text', text: '請求書ドラフト作成' },
  submit: { type: 'plain_text', text: '作成' },
  close: { type: 'plain_text', text: 'キャンセル' },
  blocks: [
    {
      type: 'input',
      block_id: 'client_name_block',
      label: { type: 'plain_text', text: '取引先名' },
      element: { type: 'plain_text_input', action_id: 'client_name_action' }
    },
    {
      type: 'input',
      block_id: 'amount_block',
      label: { type: 'plain_text', text: '金額' },
      element: { type: 'plain_text_input', action_id: 'amount_action', placeholder: { type: 'plain_text', text: '例: 300000' } }
    },
    {
      type: 'input',
      block_id: 'currency_block',
      optional: true,
      label: { type: 'plain_text', text: '通貨' },
      element: { type: 'plain_text_input', action_id: 'currency_action', initial_value: 'JPY' }
    },
    {
      type: 'input',
      block_id: 'subject_block',
      optional: true,
      label: { type: 'plain_text', text: '件名 / 案件名' },
      element: { type: 'plain_text_input', action_id: 'subject_action' }
    },
    {
      type: 'input',
      block_id: 'issue_date_block',
      optional: true,
      label: { type: 'plain_text', text: '請求日' },
      element: { type: 'datepicker', action_id: 'issue_date_action', initial_date: today }
    },
    {
      type: 'input',
      block_id: 'due_date_block',
      label: { type: 'plain_text', text: '支払期日' },
      element: { type: 'datepicker', action_id: 'due_date_action' }
    }
  ]
};

return [{ json: { trigger_id: body.trigger_id, modal_view } }];

const crypto = require('crypto');

const headers = $json.headers;
// Webhookノードのoptions.rawBody:trueは生ボディをbinary.data.data(base64)へ格納する。
// bare $binary は n8n(JS Task Runner)の静的built-ins解析で認識されず未定義になるため、
// $input経由(認識対象)でアイテムを取得してからbinaryを読む必要がある(実機検証で確認済み)。
const item = $input.first();
const rawBody = item.binary?.data?.data
  ? Buffer.from(item.binary.data.data, 'base64').toString('utf-8')
  : '';
const timestamp = headers['x-slack-request-timestamp'];
const sigHeader = headers['x-slack-signature'];
const signingSecret = $env.SLACK_SIGNING_SECRET;

const fiveMinutes = 60 * 5;
if (Math.abs(Math.floor(Date.now() / 1000) - Number(timestamp)) > fiveMinutes) {
  throw new Error('Slack request timestamp too old (possible replay)');
}

const baseString = `v0:${timestamp}:${rawBody}`;
const hmac = crypto.createHmac('sha256', signingSecret).update(baseString).digest('hex');
const expectedSig = `v0=${hmac}`;

if (expectedSig !== sigHeader) {
  throw new Error('Invalid Slack signature (interactivity)');
}

const payload = JSON.parse($json.body.payload);
return [{ json: { payload } }];

const payload = $json.payload;

if (payload.type !== 'view_submission' || payload.view?.callback_id !== 'invoice_create_modal') {
  return [{ json: { is_valid: false, error_type: 'unexpected_payload', slack_view_errors: null } }];
}

const values = payload.view.state.values;

function getText(blockId, actionId) {
  return values[blockId]?.[actionId]?.value ?? null;
}
function getDate(blockId, actionId) {
  return values[blockId]?.[actionId]?.selected_date ?? null;
}

const client_name = getText('client_name_block', 'client_name_action');
const amountRaw = getText('amount_block', 'amount_action');
const currency = getText('currency_block', 'currency_action') || 'JPY';
const subject = getText('subject_block', 'subject_action') || '';
const issue_date = getDate('issue_date_block', 'issue_date_action') || new Date().toISOString().slice(0, 10);
const due_date = getDate('due_date_block', 'due_date_action');

const errors = {};
if (!client_name) errors['client_name_block'] = '取引先名は必須です';
if (!amountRaw) {
  errors['amount_block'] = '金額は必須です';
} else if (Number.isNaN(Number(amountRaw))) {
  errors['amount_block'] = '金額は数値で入力してください';
}
if (!due_date) errors['due_date_block'] = '支払期日は必須です';

if (Object.keys(errors).length > 0) {
  return [{
    json: {
      is_valid: false,
      error_type: 'validation_error',
      slack_view_errors: { response_action: 'errors', errors }
    }
  }];
}

const now = new Date();
const dateStr = now.toISOString().slice(0, 10).replace(/-/g, '');
const randomSuffix = Math.random().toString(36).slice(2, 5).toUpperCase();
const invoice_id = `INV-${dateStr}-${randomSuffix}`;

return [{
  json: {
    is_valid: true,
    invoice_id,
    client_name,
    amount: Number(amountRaw),
    currency,
    subject,
    issue_date,
    due_date,
    status: 'draft',
    created_by: payload.user?.username || payload.user?.id,
    created_at: now.toISOString(),
    slack_user_id: payload.user?.id
  }
}];
